AISuggestion.sysmlv2:
 package "Buoy"  {

	// Imports
	private import ScalarValues::*;
	private import QuantitiesAndUnits::*;
	private import ISO80000::*;
	private import Time::*;

	// Definition of signal types
	item def __type_fromController {
		attribute IMU_xAcc : Integer;
		attribute IMU_yAcc : Integer;
		attribute IMU_zAcc : Integer;
		attribute IMU_pitchRate : Integer;
		attribute IMU_rollRate : Integer;
		attribute IMU_yawRate : Integer;
		attribute GNSS_x : Integer;
		attribute GNSS_y : Integer;
		attribute GNSS_z : Integer;
		attribute airTemp : Integer;
		attribute waterTemp : Integer;
		attribute pressure : Integer;
		attribute windSpeed : Integer;
		attribute windDirection : Integer;
		attribute windGust : Integer;
		attribute humidity : Integer;
		attribute wavePropagationDirection : Integer;
		attribute waveEnergySpectrum : Integer;
		attribute waterLevel : Integer;
	}
	item def __type_IMUData {
		attribute IMU_xAcc : Integer;
		attribute IMU_yAcc : Integer;
		attribute IMU_zAcc : Integer;
		attribute IMU_pitchRate : Integer;
		attribute IMU_rollRate : Integer;
		attribute IMU_yawRate : Integer;
	}
	item def __type_GNSSData {
		attribute GNSS_x : Integer;
		attribute GNSS_y : Integer;
		attribute GNSS_z : Integer;
	}
	item def __type_AnemometerData {
		attribute windSpeed : Integer;
		attribute windDirection : Integer;
	}
	item def __type_BarometerData {
		attribute pressure : Integer;
	}
	item def __type_AirThermometerData {
		attribute airTemp : Integer;
	}
	item def __type_WaterThermometerData {
		attribute waterTemp : Integer;
	}
	item def __type_HumiditySensorData {
		attribute humidity : Integer;
	}
	item def __type_toVHF {
		attribute IMU_xAcc : Integer;
		attribute IMU_yAcc : Integer;
		attribute IMU_zAcc : Integer;
		attribute IMU_pitchRate : Integer;
		attribute IMU_rollRate : Integer;
		attribute IMU_yawRate : Integer;
		attribute GNSS_x : Integer;
		attribute GNSS_y : Integer;
		attribute GNSS_z : Integer;
		attribute airTemp : Integer;
		attribute waterTemp : Integer;
		attribute pressure : Integer;
		attribute windSpeed : Integer;
		attribute windDirection : Integer;
		attribute windGust : Integer;
		attribute humidity : Integer;
		attribute wavePropagationDirection : Integer;
		attribute waveEnergySpectrum : Integer;
		attribute waterLevel : Integer;
	}
	item def __type_IMUData {
		attribute IMU_xAcc : Integer;
		attribute IMU_yAcc : Integer;
		attribute IMU_zAcc : Integer;
		attribute IMU_pitchRate : Integer;
		attribute IMU_rollRate : Integer;
		attribute IMU_yawRate : Integer;
	}
	item def __type_GNSSData {
		attribute GNSS_x : Integer;
		attribute GNSS_y : Integer;
		attribute GNSS_z : Integer;
	}
	item def __type_HumiditySensorData {
		attribute humidity : Integer;
	}
	item def __type_AnemometerData {
		attribute windSpeed : Integer;
		attribute windDirection : Integer;
	}
	item def __type_WaterThermometerData {
		attribute waterTemp : Integer;
	}
	item def __type_AirThermometerData {
		attribute airTemp : Integer;
	}

	// Definition of parts
	part def Block__VHFTransmitter {
		attribute IMU_xAcc : Integer;
		attribute IMU_yAcc : Integer;
		attribute IMU_zAcc : Integer;
		attribute IMU_pitchRate : Integer;
		attribute IMU_rollRate : Integer;
		attribute IMU_yawRate : Integer;
		attribute GNSS_x : Integer;
		attribute GNSS_y : Integer;
		attribute GNSS_z : Integer;
		attribute airTemp : Integer;
		attribute waterTemp : Integer;
		attribute pressure : Integer;
		attribute windSpeed : Integer;
		attribute windDirection : Integer;
		attribute windGust : Integer;
		attribute humidity : Integer;
		attribute wavePropagationDirection : Integer;
		attribute waveEnergySpectrum : Integer;
		attribute waterLevel : Integer;

		// Signals
		in item fromController :  __type_fromController;


		state entry;
		state waitingControllerData;


		state waitingControllerData {
			accept fromController(t : __type_fromController)
			do IMU_xAcc = t.IMU_xAcc
			do IMU_yAcc = t.IMU_yAcc
			do IMU_zAcc = t.IMU_zAcc
			do IMU_pitchRate = t.IMU_pitchRate
			do IMU_rollRate = t.IMU_rollRate
			do IMU_yawRate = t.IMU_yawRate
			do GNSS_x = t.GNSS_x
			do GNSS_y = t.GNSS_y
			do GNSS_z = t.GNSS_z
			do airTemp = t.airTemp
			do waterTemp = t.waterTemp
			do pressure = t.pressure
			do windSpeed = t.windSpeed
			do windDirection = t.windDirection
			do windGust = t.windGust
			do humidity = t.humidity
			do wavePropagationDirection = t.wavePropagationDirection
			do waveEnergySpectrum = t.waveEnergySpectrum
			do waterLevel = t.waterLevel
			then waitingControllerData;

		}

		state entry {
			then waitingControllerData;

		}
	}

	part def Block__Controller {
		attribute IMU_xAcc : Integer;
		attribute IMU_yAcc : Integer;
		attribute IMU_zAcc : Integer;
		attribute IMU_pitchRate : Integer;
		attribute IMU_rollRate : Integer;
		attribute IMU_yawRate : Integer;
		attribute GNSS_x : Integer;
		attribute GNSS_y : Integer;
		attribute GNSS_z : Integer;
		attribute airTemp : Integer;
		attribute waterTemp : Integer;
		attribute pressure : Integer;
		attribute windSpeed : Integer;
		attribute windDirection : Integer;
		attribute windGust : Integer;
		attribute humidity : Integer;
		attribute wavePropagationDirection : Integer;
		attribute waveEnergySpectrum : Integer;
		attribute waterLevel : Integer;

		// Signals
		in item IMUData :  __type_IMUData;

		in item GNSSData :  __type_GNSSData;

		in item AnemometerData :  __type_AnemometerData;

		in item BarometerData :  __type_BarometerData;

		in item AirThermometerData :  __type_AirThermometerData;

		in item WaterThermometerData :  __type_WaterThermometerData;

		in item HumiditySensorData :  __type_HumiditySensorData;

		out item toVHF :  __type_toVHF;


		state entry;
		state sendingMeasurements;
		state computingDerivedMeasurements;
		state readingSensorData;


		state sendingMeasurements {
		}

		state computingDerivedMeasurements {
		}

		state readingSensorData {
		}

		state entry {
		}
	}

	part def Block__IMU {
		attribute IMU_xAcc : Integer;
		attribute IMU_yAcc : Integer;
		attribute IMU_zAcc : Integer;
		attribute IMU_pitchRate : Integer;
		attribute IMU_rollRate : Integer;
		attribute IMU_yawRate : Integer;

		// Signals
		out item IMUData :  __type_IMUData;


		state entry;
		state acquiringMeasurements;


		state acquiringMeasurements {
			send IMUData{IMU_xAcc : IMU_xAcc,IMU_yAcc : IMU_yAcc,IMU_zAcc : IMU_zAcc,IMU_pitchRate : IMU_pitchRate,IMU_rollRate : IMU_rollRate,IMU_yawRate : IMU_yawRate}
			then acquiringMeasurements;

		}

		state entry {
			then acquiringMeasurements;

		}
	}

	part def Block__GNSSReceiver {
		attribute GNSS_x : Integer;
		attribute GNSS_y : Integer;
		attribute GNSS_z : Integer;

		// Signals
		out item GNSSData :  __type_GNSSData;


		state entry;
		state acquiringMeasurements;


		state acquiringMeasurements {
			send GNSSData{GNSS_x : GNSS_x,GNSS_y : GNSS_y,GNSS_z : GNSS_z}
			then acquiringMeasurements;

		}

		state entry {
			then acquiringMeasurements;

		}
	}

	part def Block__HumiditySensor {
		attribute humidity : Integer;

		// Signals
		out item HumiditySensorData :  __type_HumiditySensorData;


		state entry;
		state acquiringMeasurements;


		state acquiringMeasurements {
			send HumiditySensorData{humidity : humidity}
			then acquiringMeasurements;

		}

		state entry {
			then acquiringMeasurements;

		}
	}

	part def Block__Anemometer {
		attribute windSpeed : Integer;
		attribute windDirection : Integer;

		// Signals
		out item AnemometerData :  __type_AnemometerData;


		state entry;
		state acquiringMeasurements;


		state acquiringMeasurements {
			send AnemometerData{windSpeed : windSpeed,windDirection : windDirection}
			then acquiringMeasurements;

		}

		state entry {
			then acquiringMeasurements;

		}
	}

	part def Block__Barometer {
		attribute pressure : Integer;

		// Signals
		out item BarometerData :  __type_BarometerData;


		state entry;
		state acquiringMeasurements;
		state sendBarometerData;


		state acquiringMeasurements {
			then sendBarometerData;

		}

		state sendBarometerData {
			send BarometerData{pressure : pressure}
			then acquiringMeasurements;

		}

		state entry {
			then acquiringMeasurements;

		}
	}

	part def Block__WaterThermometer {
		attribute waterTemp : Integer;

		// Signals
		out item WaterThermometerData :  __type_WaterThermometerData;


		state entry;
		state acquiringMeasurements;


		state acquiringMeasurements {
			send WaterThermometerData{waterTemp : waterTemp}
			then acquiringMeasurements;

		}

		state entry {
			then acquiringMeasurements;

		}
	}

	part def Block__AirThermometer {
		attribute airTemp : Integer;

		// Signals
		out item AirThermometerData :  __type_AirThermometerData;


		state entry;
		state acquiringMeasurements;


		state acquiringMeasurements {
			send AirThermometerData{airTemp : airTemp}
			then acquiringMeasurements;

		}

		state entry {
			then acquiringMeasurements;

		}
	}

	// Usage of parts
	part VHFTransmitter : Block__VHFTransmitter {
	}

	part Controller : Block__Controller {
	}

	part IMU : Block__IMU {
	}

	part GNSSReceiver : Block__GNSSReceiver {
	}

	part HumiditySensor : Block__HumiditySensor {
	}

	part Anemometer : Block__Anemometer {
	}

	part Barometer : Block__Barometer {
	}

	part WaterThermometer : Block__WaterThermometer {
	}

	part AirThermometer : Block__AirThermometer {
	}

	// Connection between signals
	enum def CommunicationKind {
		synchronous;
		asynchronous;
	}

	connection def ConnectionInfoSync {
		attribute communicationKind : CommunicationKind;
		attribute isPrivate   : Boolean ;
		attribute isLossy     : Boolean ;
	}


	connection WaterThermometer_WaterThermometerData__Controller_WaterThermometerData : ConnectionInfoSync
	connect WaterThermometer.WaterThermometerData to Controller.WaterThermometerData  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connection AirThermometer_AirThermometerData__Controller_AirThermometerData : ConnectionInfoSync
	connect AirThermometer.AirThermometerData to Controller.AirThermometerData  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connection HumiditySensor_HumiditySensorData__Controller_HumiditySensorData : ConnectionInfoSync
	connect HumiditySensor.HumiditySensorData to Controller.HumiditySensorData  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connection Anemometer_AnemometerData__Controller_AnemometerData : ConnectionInfoSync
	connect Anemometer.AnemometerData to Controller.AnemometerData  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connection Barometer_BarometerData__Controller_BarometerData : ConnectionInfoSync
	connect Barometer.BarometerData to Controller.BarometerData  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connection GNSSReceiver_GNSSData__Controller_GNSSData : ConnectionInfoSync
	connect GNSSReceiver.GNSSData to Controller.GNSSData  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connection IMU_IMUData__Controller_IMUData : ConnectionInfoSync
	connect IMU.IMUData to Controller.IMUData  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connection Controller_toVHF__VHFTransmitter_fromController : ConnectionInfoSync
	connect Controller.toVHF to VHFTransmitter.fromController  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}


}
